query:
SELECT id, document_type, title, file_name, file_url, mime_type
FROM agency_documents
WHERE id IN (
  SELECT source_document_id FROM claims WHERE id = 2730001
);

SELECT id, document_type, title, file_name, file_url, mime_type
FROM agency_documents
ORDER BY created_at DESC
LIMIT 10;

